CREATE DATABASE IF NOT EXISTS healthcaredb;
USE healthcaredb;
DROP TABLE IF EXISTS `pre`;
CREATE TABLE `pre` (
  `pat_id` varchar(18) NOT NULL DEFAULT '',
  `diagnosis` longtext,
  `diet` longtext,
  `activity` varchar(50) DEFAULT NULL,
  `drugs` longtext,
  `quantity` longtext,
  `dose` longtext,
  `duration` longtext,
  `advice` longtext,
  `comments` longtext,
  `name_hos` varchar(50) DEFAULT NULL,
  `entrydate` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `apptdate` datetime DEFAULT NULL,
  `docrg_no` varchar(50) DEFAULT NULL,
  `preid` varchar(20) DEFAULT NULL,
  `serno` int NOT NULL,
  PRIMARY KEY (`pat_id`,`entrydate`,`serno`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

LOCK TABLES `pre` WRITE;
