UNLOCK TABLES;

CREATE OR REPLACE VIEW AggregationModel AS
SELECT 
    pat_id, 
    -- This part is the "Aggregation" technique: 
    -- It groups all diagnoses for one patient into a single string.
    GROUP_CONCAT(DISTINCT diagnosis ORDER BY diagnosis ASC SEPARATOR ', ') AS disease_transaction,
    COUNT(diagnosis) AS disease_count
FROM pre
-- Filters out empty diagnoses to ensure data quality
WHERE diagnosis IS NOT NULL AND diagnosis != ''
GROUP BY pat_id
-- For co-occurrence analysis, we only want patients with more than one disease
HAVING disease_count > 1;

